const dashboardPanelIds = [
  "schedule",
  "notifications",
  "leadFollowups",
  "quoteFollowups",
  "poRequests",
  "variations",
  "approvedQuotes",
  "timesheets",
] as const;

type DashboardPanelId = (typeof dashboardPanelIds)[number];
type DashboardPanelSize = "wide" | "side" | "standard";
type DashboardLayout = {
  order: DashboardPanelId[];
  hidden: DashboardPanelId[];
  updatedAt?: string;
};

const dashboardPanelMeta: Record<DashboardPanelId, { label: string; size: DashboardPanelSize }> = {
  schedule: { label: "Weekly schedule", size: "wide" },
  notifications: { label: "Action notifications", size: "side" },
  leadFollowups: { label: "Lead follow-ups", size: "standard" },
  quoteFollowups: { label: "Quote follow-ups", size: "standard" },
  poRequests: { label: "PO requests", size: "standard" },
  variations: { label: "Variations", size: "standard" },
  approvedQuotes: { label: "Approved quotes", size: "standard" },
  timesheets: { label: "Timesheets", size: "standard" },
};

const defaultDashboardLayout: DashboardLayout = {
  order: [...dashboardPanelIds],
  hidden: [],
};

function isDashboardPanelId(value: unknown): value is DashboardPanelId {
  return typeof value === "string" && (dashboardPanelIds as readonly string[]).includes(value);
}

function normalizeDashboardLayout(value: unknown): DashboardLayout {
  const record = value && typeof value === "object" && !Array.isArray(value)
    ? (value as Partial<DashboardLayout>)
    : {};
  const seen = new Set<DashboardPanelId>();
  const order = [
    ...(Array.isArray(record.order) ? record.order.filter(isDashboardPanelId) : []),
    ...dashboardPanelIds,
  ].filter((panelId): panelId is DashboardPanelId => {
    if (!isDashboardPanelId(panelId) || seen.has(panelId)) return false;
    seen.add(panelId);
    return true;
  });
  const hidden = (Array.isArray(record.hidden) ? record.hidden.filter(isDashboardPanelId) : [])
    .filter((panelId, index, list) => list.indexOf(panelId) === index);

  return {
    order,
    hidden: hidden.length >= dashboardPanelIds.length ? [] : hidden,
    updatedAt: typeof record.updatedAt === "string" ? record.updatedAt : undefined,
  };
}

function normalizeDashboardLayouts(value: unknown): Record<string, DashboardLayout> {
  if (!value || typeof value !== "object" || Array.isArray(value)) return {};
  return Object.fromEntries(
    Object.entries(value as Record<string, unknown>)
      .filter(([key]) => key.trim().length > 0)
      .map(([key, layout]) => [key, normalizeDashboardLayout(layout)]),
  );
}

function safeLoadStoredJson<T>(key: string, fallback: T): T {
  if (typeof window === "undefined") return fallback;

  const raw = window.localStorage.getItem(key);
  if (!raw) return fallback;
  try {
    return JSON.parse(raw) as T;
  } catch {
    return fallback;
  }
}

function safeSaveStoredJson<T>(key: string, value: T) {
  if (typeof window === "undefined") return;
  try {
    window.localStorage.setItem(key, JSON.stringify(value));
  } catch {
    // Optional persistence is best effort only.
  }
}

function createTrustedEmployeeSession(employeeId: string): TrustedEmployeeSession {
  const issuedAt = new Date();
  const trustedUntil = new Date(issuedAt);
  trustedUntil.setDate(trustedUntil.getDate() + TRUSTED_EMPLOYEE_SESSION_DAYS);

  return {
    employeeId,
    issuedAt: issuedAt.toISOString(),
    trustedUntil: trustedUntil.toISOString(),
  };
}

function resolveTrustedEmployeeSession(
  value: string | TrustedEmployeeSession | null,
  employees: EmployeeCard[],
) {
  const employeeId = typeof value === "string" ? value : value?.employeeId;
  if (!employeeId) return null;

  if (value && typeof value !== "string") {
    const trustedUntilTime = Date.parse(value.trustedUntil);
    if (!Number.isFinite(trustedUntilTime) || trustedUntilTime < Date.now()) {
      return null;
    }
  }

  return employees.some((employee) => employee.id === employeeId) ? employeeId : null;
}

function clearTrustedEmployeeSession() {
  if (typeof window === "undefined") return;
  window.localStorage.removeItem(STORAGE_KEYS.activeEmployeeSession);
}

function normalizeClientIdentity(value: string) {
  return value.trim().toLowerCase();
}

type LeadCustomerMatch = {
  client: ClientRecord;
  matchScore: number;
  matchReason: string;
};

type CustomerLookupDraft = {
  clientId?: string;
  customerName: string;
  email?: string;
  phone?: string;
  address?: string;
};

function normalizePhone(value: string) {
  return value.replace(/[^\d]/g, "");
}

function buildLeadCustomerMatches(draft: CustomerLookupDraft, clients: ClientRecord[], sites: ClientSite[]): LeadCustomerMatch[] {
  if (draft.clientId) return [];

  const draftName = normalizeClientIdentity(draft.customerName);
  const draftEmail = normalizeClientIdentity(draft.email ?? "");
  const draftPhone = normalizePhone(draft.phone ?? "");
  const draftAddress = normalizeClientIdentity(draft.address ?? "");

  if (![draftName, draftEmail, draftPhone, draftAddress].some((value) => value.length >= 2)) return [];

  const clientMatches = clients
    .map((client) => {
      let score = 0;
      const reasons: string[] = [];

      const clientName = normalizeClientIdentity(client.name);
      const clientEmail = normalizeClientIdentity(client.email);
      const clientPhone = normalizePhone(client.phone);
      const billingAddress = normalizeClientIdentity(client.billingAddress);

      if (draftEmail && clientEmail === draftEmail) {
        score += 100;
        reasons.push("email");
      }

      if (draftPhone && clientPhone && clientPhone === draftPhone) {
        score += 95;
        reasons.push("phone");
      }

      if (draftName) {
        if (clientName === draftName) {
          score += 90;
          reasons.push("exact name");
        } else if (clientName.includes(draftName) || draftName.includes(clientName)) {
          score += 55;
          reasons.push("partial name");
        }
      }

      if (draftAddress && billingAddress && billingAddress.includes(draftAddress)) {
        score += 25;
        reasons.push("billing address");
      }

      if (draftAddress) {
        const siteMatch = sites.find(
          (site) => site.clientId === client.id && normalizeClientIdentity(site.address).includes(draftAddress),
        );
        if (siteMatch) {
          score += 30;
          reasons.push(`site: ${siteMatch.name}`);
        }
      }

      if (score < 30) return null;

      return {
        client,
        matchScore: score,
        matchReason: reasons.join(", "),
      };
    })
    .filter((item): item is LeadCustomerMatch => item !== null)
    .sort((first, second) => second.matchScore - first.matchScore)
    .slice(0, 8);

  return clientMatches;
}

function makeClientReference(existingClients: ClientRecord[]) {
  const numbers = existingClients
    .map((client) => {
      const found = client.accountReference.match(/\d+/g)?.join("");
      return found ? Number(found) : 0;
    })
    .filter((number) => Number.isFinite(number));
  const next = Math.max(1000, ...numbers) + 1;
  return `C-${next}`;
}

function makeSiteName(address: string) {
  return (address.split(",")[0]?.trim() || "New site").slice(0, 64);
}

function resolveLeadCustomer(
  draft: LeadDraft,
  existingClients: ClientRecord[],
): ClientRecord | undefined {
  const draftName = normalizeClientIdentity(draft.customerName);
  const draftEmail = normalizeClientIdentity(draft.email);
  const draftPhone = normalizePhone(draft.phone);

  const emailMatch = existingClients.find((client) =>
    draftEmail && normalizeClientIdentity(client.email) === draftEmail,
  );
  if (emailMatch) return emailMatch;

  if (draftPhone) {
    const phoneMatch = existingClients.find((client) => normalizePhone(client.phone) === draftPhone);
    if (phoneMatch) return phoneMatch;
  }

  const nameMatch = existingClients.find(
    (client) => normalizeClientIdentity(client.name) === draftName || draftName.includes(normalizeClientIdentity(client.name)),
  );
  if (nameMatch) return nameMatch;

  return undefined;
}

function buildClientFromLead(draft: LeadDraft, clients: ClientRecord[]) {
  const address = draft.address.trim();
  const token = `${Date.now()}-${Math.round(Math.random() * 1000)}`;
  const newClient: ClientRecord = {
    id: `client-${token}`,
    name: draft.customerName.trim() || "New customer",
    accountReference: makeClientReference(clients),
    status: "Prospect",
    primaryContact: draft.customerName.trim(),
    email: draft.email.trim() || `${token}@example.com`,
    phone: draft.phone.trim() || "Pending",
    billingAddress: address || "Pending address",
    commercialOwner: "TBD",
    notes: "Created from lead intake.",
  };

  const newSite: ClientSite | undefined = address
        ? {
        id: `site-${token}`,
        clientId: newClient.id,
        name: makeSiteName(address),
        address,
        accessNotes: "To confirm before first visit.",
        primaryContact: draft.customerName.trim(),
        serviceLine: "New work",
        nextVisit: "To be scheduled",
      }
    : undefined;

  return { newClient, newSite };
}

function resolveLeadSiteFromDraft(
  draft: Pick<LeadDraft, "siteId" | "address" | "customerName">,
  client: ClientRecord | undefined,
  sites: ClientSite[],
) {
  if (draft.siteId) {
    const explicitSite = sites.find((site) =>
      site.id === draft.siteId && (!client || site.clientId === client.id),
    );
    if (explicitSite) return explicitSite;
  }

  if (!client) return undefined;

  return (
    sites.find((site) => site.clientId === client.id && normalizeClientIdentity(site.address) === normalizeClientIdentity(draft.address))
    ?? (draft.address
      ? {
          id: `site-${Date.now()}-${Math.round(Math.random() * 1000)}`,
          clientId: client.id,
          name: makeSiteName(draft.address),
          address: draft.address,
          accessNotes: "To be confirmed before first visit.",
          primaryContact: draft.customerName,
          serviceLine: "New work",
          nextVisit: "To be scheduled",
        }
      : undefined)
  );
}

function leadMapEmbedUrl(address: string) {
  const query = encodeURIComponent(address.trim());
  return `https://www.google.com/maps?q=${query}&output=embed`;
}

function leadMapSearchUrl(address: string) {
  const query = encodeURIComponent(address.trim());
  return `https://www.google.com/maps/search/?api=1&query=${query}`;
}

function leadAddressFromParts(parts?: Partial<LeadAddressParts>) {
  if (!parts) return "";
  return [parts.line1, parts.line2, parts.town, parts.county, parts.postcode]
    .map((part) => part?.trim())
    .filter(Boolean)
    .join(", ");
}

function leadAddressPartsFromAddress(address: string, postcodeHint = ""): LeadAddressParts {
  const postcode = (postcodeHint || address.match(/[A-Z]{1,2}\d[A-Z\d]?\s*\d[A-Z]{2}$/i)?.[0] || "").toUpperCase();
  const withoutPostcode = postcode
    ? address.replace(new RegExp(`${postcode.replace(/\s+/g, "\\s*")}$`, "i"), "").replace(/,\s*$/, "")
    : address;
  const parts = withoutPostcode.split(",").map((part) => part.trim()).filter(Boolean);
  const tail = parts.slice(1);
  return {
    line1: parts[0] ?? "",
    line2: tail.length > 2 ? tail.slice(0, -2).join(", ") : "",
    town: tail.length >= 2 ? tail[tail.length - 2] ?? "" : tail[0] ?? "",
    county: tail.length >= 2 ? tail[tail.length - 1] ?? "" : "",
    postcode,
  };
}

function normaliseLeadContact(contact: LeadContact) {
  return {
    ...contact,
    name: contact.name.trim(),
    role: contact.role.trim() || "Additional contact",
    phone: contact.phone.trim(),
    email: contact.email.trim(),
    notes: contact.notes.trim(),
  };
}

