const defaultEngineerFlowTemplates = [
  defaultBoilerFlowTemplate,
  boilerServiceFlowTemplate,
  generalWorksFlowTemplate,
];

const costCentreFlowAssignments = costCentreTemplates.map((templateName) => {
  const flow = defaultEngineerFlowTemplates.find((template) => template.appliesTo.includes(templateName)) ?? generalWorksFlowTemplate;
  return {
    templateName,
    flowId: flow.id,
    flowName: flow.name,
  };
});

const defaultCostCentreFlowAssignmentMap = costCentreFlowAssignments.reduce<Record<string, string>>((assignments, assignment) => {
  assignments[assignment.templateName] = assignment.flowId;
  return assignments;
}, {});

function normalizeEngineerFlowTemplate(template: EngineerFlowTemplate): EngineerFlowTemplate {
  if (template.id !== defaultBoilerFlowTemplate.id) return template;
  return {
    ...template,
    appliesTo: ["Boiler replacement"],
  };
}

function normalizeEngineerFlowTemplates(templates: EngineerFlowTemplate[], legacyTemplate?: EngineerFlowTemplate) {
  const merged = new Map<string, EngineerFlowTemplate>();

  defaultEngineerFlowTemplates.forEach((template) => merged.set(template.id, template));
  if (legacyTemplate) {
    merged.set(legacyTemplate.id, normalizeEngineerFlowTemplate(legacyTemplate));
  }
  templates.forEach((template) => merged.set(template.id, normalizeEngineerFlowTemplate(template)));

  return Array.from(merged.values()).filter((template) => template.name.trim() && template.steps.length > 0);
}

function normalizeCostCentreAssignments(assignments: Record<string, string>, typeOptions: string[]) {
  return typeOptions.reduce<Record<string, string>>((nextAssignments, typeName) => {
    nextAssignments[typeName] =
      assignments[typeName] ??
      defaultCostCentreFlowAssignmentMap[typeName] ??
      generalWorksFlowTemplate.id;
    return nextAssignments;
  }, {});
}

const blankEmployeeAvailability = weekDays.reduce((acc, day) => {
  acc[day] = { active: false, from: "09:00", to: "17:00" };
  return acc;
}, {} as EmployeeAvailability);

function normalizeLoginInput(value: string) {
  return value.trim().toLowerCase();
}

function getEmployeeInitials(name: string) {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  if (parts.length === 0) return "N";
  return parts.slice(0, 2).map((part) => part[0]?.toUpperCase() ?? "").join("");
}

function makeDefaultEmployeeUsername(employee: Pick<EmployeeCard, "name" | "profile">) {
  const emailUser = employee.profile?.email?.split("@")[0];
  if (emailUser?.trim()) return normalizeLoginInput(emailUser);
  return normalizeLoginInput(employee.name).replace(/[^a-z0-9]+/g, ".");
}

function makeDefaultEmployeeLogin(employee: EmployeeCard) {
  return {
    username: makeDefaultEmployeeUsername(employee),
    password: "EWG2026",
    enabled: true,
  };
}

function withDefaultEmployeeLogin(employee: EmployeeCard): EmployeeCard {
  const defaultLogin = makeDefaultEmployeeLogin(employee);
  return {
    ...employee,
    login: {
      ...defaultLogin,
      ...(employee.login ?? {}),
      username: employee.login?.username?.trim() || defaultLogin.username,
      password: employee.login?.password ?? defaultLogin.password,
      enabled: employee.login?.enabled ?? defaultLogin.enabled,
    },
  };
}

function normalizeEmployeeCards(records: EmployeeCard[]) {
  const normalized = records.map(withDefaultEmployeeLogin);
  const seedById = new Map(seedEmployees.map((employee) => [employee.id, employee]));
  const retiredDemoEmployeeIds = new Set(["emp-kerry", "emp-scott", "emp-jamie"]);
  const retiredDemoEmployeeNames = new Set(["Kerry Watson", "Scott Reid", "Jamie Fox", "Chris Watson"]);
  const targetIds = new Set(seedEmployees.map((employee) => employee.id));

  const nextEmployees = seedEmployees.map((template) => {
    const existing = normalized.find((employee) => employee.id === template.id);
    if (!existing) return withDefaultEmployeeLogin(template);

    return withDefaultEmployeeLogin({
      ...template,
      ...existing,
      id: template.id,
      name: existing.name.trim() || template.name,
      role: existing.role || template.role,
      permissions: existing.permissions ?? template.permissions,
      profile: {
        ...template.profile,
        ...existing.profile,
      },
    });
  });

  normalized.forEach((employee) => {
    if (targetIds.has(employee.id)) return;
    if (retiredDemoEmployeeIds.has(employee.id)) return;
    if (retiredDemoEmployeeNames.has(employee.name)) return;
    if (seedById.has(employee.id)) return;
    nextEmployees.push(employee);
  });

  return nextEmployees;
}

