  function sendSelectedInvoiceEmail() {
    if (!selectedInvoice || !selectedInvoiceEmailDraft) return;
    if (!selectedInvoiceEmailDraft.to.trim()) {
      showNotice("Add a recipient before sending the invoice.");
      return;
    }
    const sentAt = workflowTimestamp();
    const outlookMessageId = `outlook-${selectedInvoice.ref.toLowerCase()}-${Date.now()}`;
    const sourceJob =
      selectedInvoice.sourceType === "job"
        ? jobs.find((job) => job.id === selectedInvoice.sourceId) ?? null
        : null;
    setInvoices((current) =>
      current.map((invoice) =>
        invoice.id === selectedInvoice.id
          ? {
              ...invoice,
              status: "Sent",
              sentTo: selectedInvoiceEmailDraft.to.trim(),
              sentAt,
              outlookMessageId,
            }
          : invoice,
      ),
    );
    if (sourceJob) {
      setJobs((current) =>
        current.map((job) =>
          job.id === sourceJob.id
            ? {
                ...job,
                status: "Invoiced",
                health: "green",
                next: `Invoice ${selectedInvoice.ref} sent. Await payment.`,
                due: selectedInvoice.dueDate,
              }
            : job,
        ),
      );
    }
    logAuditEvent({
      actor: activeEmployee?.name ?? "NeXa user",
      action: "emailed",
      recordType: "invoice",
      recordId: selectedInvoice.id,
      summary: `Invoice ${selectedInvoice.ref} emailed from NeXa via Outlook to ${selectedInvoiceEmailDraft.to}.`,
      source: "outlook draft",
      importance: "high",
    });
    if (sourceJob) {
      logAuditEvent({
        actor: activeEmployee?.name ?? "NeXa user",
        action: "invoiced",
        recordType: "job",
        recordId: sourceJob.id,
        summary: `${sourceJob.ref} marked Invoiced after ${selectedInvoice.ref} was emailed to ${selectedInvoiceEmailDraft.to}.`,
        source: "invoice email",
        importance: "high",
      });
    }
    addCommunicationRecord({
      recordType: "invoice",
      recordId: selectedInvoice.id,
      relatedJobId: selectedInvoice.sourceType === "job" ? selectedInvoice.sourceId : undefined,
      direction: "outbound",
      channel: "Outlook",
      subject: selectedInvoiceEmailDraft.subject,
      body: selectedInvoiceEmailDraft.body,
      from: "accounts@errolwatsongroup.co.uk",
      to: selectedInvoiceEmailDraft.to.trim(),
      cc: selectedInvoiceEmailDraft.cc.trim(),
      messageId: outlookMessageId,
      status: "Sent",
    });
    showNotice(sourceJob ? `Invoice ${selectedInvoice.ref} sent and ${sourceJob.ref} marked invoiced.` : `Invoice ${selectedInvoice.ref} sent and logged.`);
  }

  function submitSelectedValuation() {
    if (!selectedInvoice || !selectedInvoiceEmailDraft) return;
    if (!selectedInvoiceEmailDraft.to.trim()) {
      showNotice("Add a recipient before submitting the valuation.");
      return;
    }

    const subject = `Application for payment - ${selectedInvoice.sourceName}`;
    const body = `Hi,\n\nPlease find our application for payment for ${selectedInvoice.sourceName}.\n\nApplication value excluding VAT: ${currency(selectedInvoice.chargeTotal)}.\nVAT: ${currency(selectedInvoice.chargeTotal * (selectedInvoice.vatRate / 100))}.\nTotal applied for: ${currency(selectedInvoiceFinancials.grandTotal)}.\n\nKind regards,\nNeXa`;
    const messageId = `outlook-valuation-${selectedInvoice.ref.toLowerCase()}-${Date.now()}`;

    addCommunicationRecord({
      recordType: "invoice",
      recordId: selectedInvoice.id,
      relatedJobId: selectedInvoice.sourceType === "job" ? selectedInvoice.sourceId : undefined,
      direction: "outbound",
      channel: "Outlook",
      subject,
      body,
      from: "accounts@errolwatsongroup.co.uk",
      to: selectedInvoiceEmailDraft.to.trim(),
      cc: selectedInvoiceEmailDraft.cc.trim(),
      messageId,
      status: "Sent",
    });

    logAuditEvent({
      actor: activeEmployee?.name ?? "NeXa user",
      action: "valuation submitted",
      recordType: "invoice",
      recordId: selectedInvoice.id,
      summary: `Application for payment submitted for ${selectedInvoice.sourceName} to ${selectedInvoiceEmailDraft.to}.`,
      source: "outlook draft",
      importance: "high",
    });

    if (selectedInvoiceSourceJob) {
      logAuditEvent({
        actor: activeEmployee?.name ?? "NeXa user",
        action: "valuation submitted",
        recordType: "job",
        recordId: selectedInvoiceSourceJob.id,
        summary: `Application for payment submitted from ${selectedInvoice.ref}.`,
        source: "invoice record",
        importance: "high",
      });
    }

    showNotice("Application for payment submitted and logged.");
  }

