  async function persistQuotePatch(quoteId: string, patch: Partial<Quote>) {
    const response = await fetch(`/api/quotes/${quoteId}`, {
      method: "PATCH",
      headers: { ...requestHeaders, "Content-Type": "application/json" },
      body: JSON.stringify(patch),
    });
    if (!response.ok) throw new Error("Unable to update quote");
    const updated = (await response.json()) as Quote;
    setQuotes((current) => current.map((quote) => (quote.id === updated.id ? updated : quote)));
    return updated;
  }

  async function sendSelectedQuoteToSimpro() {
    if (!selectedQuote) return;
    setIsSendingQuoteToSimpro(true);
    setSectionError(null);

    try {
      const response = await fetch(`/api/quotes/${selectedQuote.id}/simpro-push`, {
        method: "POST",
        headers: { ...requestHeaders, "Content-Type": "application/json" },
        body: JSON.stringify({
          actor: activeEmployee?.name ?? "NeXa user",
          costCentres: quoteCostCentres[selectedQuote.id] ?? [],
        }),
      });
      const result = (await response.json().catch(() => null)) as {
        quote?: Quote;
        exportRecord?: SimproExportRecord;
        auditEvent?: AuditEvent;
        error?: string;
      } | null;

      if (!result?.quote || !result.exportRecord) {
        throw new Error(result?.error ?? "Unable to create Simpro handoff.");
      }

      const updatedQuote = result.quote;
      const exportRecord = result.exportRecord;
      const auditEvent = result.auditEvent;

      setQuotes((current) => current.map((quote) => (quote.id === updatedQuote.id ? updatedQuote : quote)));
      setSimproExports((current) => [
        exportRecord,
        ...current.filter((item) => item.id !== exportRecord.id),
      ]);
      if (auditEvent) {
        setAuditEvents((current) => [
          auditEvent,
          ...current.filter((event) => event.id !== auditEvent.id),
        ]);
      }

      if (exportRecord.status === "Sent") {
        showNotice(`${selectedQuote.ref} sent to Simpro${exportRecord.simproQuoteId ? ` as ${exportRecord.simproQuoteId}` : ""}.`);
      } else if (exportRecord.status === "Failed") {
        const message = exportRecord.error ?? "Simpro bridge failed.";
        setSectionError(message);
        showNotice(message);
      } else {
        const missingSetup = exportRecord.setupRequired || "SIMPRO_QUOTE_PUSH_URL";
        showNotice(`${selectedQuote.ref} saved in NeXa's Simpro queue. It has not reached Simpro yet because ${missingSetup} is not configured.`);
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unable to create Simpro handoff.";
      setSectionError(message);
      showNotice(message);
    } finally {
      setIsSendingQuoteToSimpro(false);
    }
  }

  async function sendSelectedQuoteEmail() {
    if (!selectedQuote || !selectedQuoteEmailDraft) return;
    if (!selectedQuoteEmailDraft.to.trim()) {
      showNotice("Add a recipient before sending the quote.");
      return;
    }

    const portalToken = selectedQuote.portalToken ?? makeQuotePortalToken(selectedQuote);
    const portalBaseUrl = typeof window !== "undefined" ? window.location.origin : "http://127.0.0.1:3000";
    const portalUrl = selectedQuote.portalUrl ?? `${portalBaseUrl}/client/quotes/${portalToken}`;
    const sentAt = workflowTimestamp();
    const outlookMessageId = `outlook-${selectedQuote.ref.toLowerCase()}-${Date.now()}`;

    try {
      await persistQuotePatch(selectedQuote.id, {
        status: "Sent" as QuoteStatus,
        next: "Await customer response",
        portalToken,
        portalUrl,
        outlookMessageId,
        sentAt,
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unable to send quote right now.";
      setSectionError(message);
      showNotice(message);
      return;
    }

    logAuditEvent({
      actor: activeEmployee?.name ?? "NeXa user",
      action: "emailed",
      recordType: "quote",
      recordId: selectedQuote.id,
      summary: `${selectedQuote.ref} emailed from NeXa via Outlook to ${selectedQuoteEmailDraft.to} with ${documentLayouts.find((layout) => layout.key === selectedQuoteEmailDraft.layout)?.label ?? "quote"} PDF attached. Portal link: ${portalUrl}.`,
      source: "outlook draft",
      importance: "normal",
    });
    addCommunicationRecord({
      recordType: "quote",
      recordId: selectedQuote.id,
      relatedJobId: selectedQuote.convertedJobId,
      direction: "outbound",
      channel: "Outlook",
      subject: selectedQuoteEmailDraft.subject,
      body: `${selectedQuoteEmailDraft.body}\n\nPortal link: ${portalUrl}`,
      from: "office@errolwatsongroup.co.uk",
      to: selectedQuoteEmailDraft.to.trim(),
      cc: selectedQuoteEmailDraft.cc.trim(),
      messageId: outlookMessageId,
      status: "Sent",
    });

    showNotice("Quote sent from NeXa and captured against the quote.");
  }

