                                  updateCostCentreNumberInput(`takeoff:${selectedQuoteCostCentre.id}:${row.id}:unitCost`, event.target.value, (unitCost) => {
                                    updateTakeoffRow(selectedQuoteCostCentre.id, row.id, { unitCost });
                                  });
